// eventLevelBadgeClass returns the badge CSS class for an event level.
func eventLevelBadgeClass(level string) string {
	switch level {
	case "error":
		return "badge-danger"
	case "warning":
		return "badge-warning"
	default:
		return "badge-info"
	}
}

